  const info = {
    whatsapp_id: whatsappId,
    nombre: null,
    presupuesto: null,
    zona: null,
    tipo_propiedad: null,
    forma_pago: null,
    intencion: null,
    caracteristicas_buscadas: null,
    caracteristicas_venta: null,
    propiedad_interes: null,
    estado: null,
    ultima_interaccion: new Date().toISOString()
  };

  // в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
  // CALIFICACIГ“N AUTOMГЃTICA POR MENSAJES
  // в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
  try {
    // рџ”’ PROTECCIГ“N: Si el estado actual en DB ya es llamada, busqueda o visita, no tocar
    const estadoActual = $('SQL - Cancelar Seguimiento').first()?.json?.estado || null;

    if (['llamada', 'busqueda', 'visita'].includes(estadoActual)) {
      info.estado = estadoActual;
      console.log(`рџ”’ Estado protegido: "${estadoActual}" вЂ” no se recalcula`);
    } else {
      // CalificaciГіn normal por cantidad de mensajes
      const historialData = $('Formatear Historial').item?.json;
      const totalMensajes = historialData?.totalMensajes || 0;

      if (totalMensajes <= 2) {
        info.estado = 'frio';
      } else if (totalMensajes <= 15) {
        info.estado = 'tibio';
      } else {
        info.estado = 'caliente';
      }
      console.log(`рџ“Љ Lead calificado como "${info.estado}" (${totalMensajes} mensajes)`);
    }
  } catch (e) {
    info.estado = 'frio';
    console.log('рџ“Љ Lead calificado como "frio" por defecto (sin historial)');
  }

  const fullContext = (userMsg + ' ' + agentMsg).toLowerCase();
  console.log('Contexto completo:', fullContext.substring(0, 200));

  // Extraer intenciГіn (comprar o vender)
  if (fullContext.match(/\b(quiero comprar|busco comprar|interesa comprar|me interesa|quiero una propiedad|estoy buscando|necesito comprar|busco|info|informaciГіn)\b/)) {
    info.intencion = 'comprar';
  } else if (fullContext.match(/\b(quiero vender|vender mi|tengo una propiedad|quiero publicar|poner en venta)\b/)) {
    info.intencion = 'vender';
  }

  // Extraer tipo de propiedad
  const tiposPropiedad = {
    'departamento': /\b(departamento|depto|dto|dpto)\b/,
    'casa': /\b(casa|vivienda)\b/,
    'ph': /\b(ph|p\.h\.|petit hotel)\b/,
    'terreno': /\b(terreno|lote)\b/,
    'local': /\b(local comercial|local)\b/,
    'oficina': /\b(oficina)\b/,
    'cochera': /\b(cochera|garage|garaje)\b/
  };

  for (const [tipo, regex] of Object.entries(tiposPropiedad)) {
    if (fullContext.match(regex)) {
      info.tipo_propiedad = tipo;
      break;
    }
  }

  // Extraer presupuesto
  const presupuestoPatterns = [
    /(?:presupuesto|hasta|mГЎximo|budget|tengo)[\s:de]*(?:usd?[\s$]*)?([\d]+[\\.,]?\d*)\s*(?:mil|k|millones?|m)?/i,
    /(?:usd?[\s$]*)([\d]+[\\.,]?\d*)\s*(?:mil|k|millones?|m)/i,
    /([\d]+[\\.,]?\d*)\s*(?:mil|k|millones?|m)\s*(?:dГіlares|dolares|usd|pesos)?/i
  ];

  for (const pattern of presupuestoPatterns) {
    const presupuestoMatch = fullContext.match(pattern);
    if (presupuestoMatch) {
      let monto = parseFloat(presupuestoMatch[1].replace(',', '.'));
      if (fullContext.match(/\bmillones?\b/)) monto *= 1000000;
      else if (fullContext.match(/\b(mil|k)\b/)) monto *= 1000;
      info.presupuesto = monto;
      console.log('Presupuesto encontrado:', monto);
      break;
    }
  }

  // Extraer zona
  const zonaPatterns = [
    /\b(?:en|zona|barrio|ubicaciГіn|ubicado en?|por)\s+(?:de\s+|la\s+)?([a-zГЎГ©Г­ГіГєГ±\s]+?)(?:\s|,|\.|\?|$)/i,
    /\b(palermo|belgrano|recoleta|puerto madero|caballito|villa crespo|colegiales|nuГ±ez|saavedra|microcentro|san telmo|balvanera|almagro|flores|barracas|monserrat|retiro|once|abasto|congreso|chacarita|parque patricios|boedo|barrio norte|zona norte|zona sur|zona oeste|centro|city bell|la plata|gonnet|tolosa|villa elisa)\b/i
  ];

  for (const pattern of zonaPatterns) {
    const zonaMatch = fullContext.match(pattern);
    if (zonaMatch) {
      const zonaCandidato = zonaMatch[1] ? zonaMatch[1].trim() : zonaMatch[0].trim();
      if (zonaCandidato.length > 2 && zonaCandidato.length < 50) {
        info.zona = zonaCandidato.charAt(0).toUpperCase() + zonaCandidato.slice(1);
        console.log('Zona encontrada:', info.zona);
        break;
      }
    }
  }

  // Extraer forma de pago
  if (fullContext.match(/\b(contado|efectivo|cash|al contado|pago contado|en efectivo|seria en efectivo|compra seria en efectivo)\b/)) {
    info.forma_pago = 'contado';
    console.log('Forma de pago: contado');
  } else if (fullContext.match(/\b(financiado|financiaciГіn|cuotas|en cuotas|crГ©dito|a crГ©dito)\b/)) {
    info.forma_pago = 'financiado';
  } else if (fullContext.match(/\b(hipotecario|prГ©stamo|prГ©stamo hipotecario|con hipoteca|por banco|busqueda es por banco)\b/)) {
    info.forma_pago = 'hipotecario';
  } else if (fullContext.match(/\b(mixto|parte contado|parte financiado)\b/)) {
    info.forma_pago = 'mixto';
  }

  // Extraer caracterГ­sticas buscadas
  const caracBuscadas = [];

  const ambMatch = fullContext.match(/\b(\d+)\s*(?:ambiente|ambientes|amb)\b/);
  if (ambMatch) {
    caracBuscadas.push(`${ambMatch[1]} ambientes`);
  }

  const dormMatch = fullContext.match(/\b(\d+)\s*(?:dormitorio|dormitorios|habitaciГіn|habitaciones|cuarto|cuartos)\b/);
  if (dormMatch) {
    caracBuscadas.push(`${dormMatch[1]} dormitorios`);
  }

  const baГ±oMatch = fullContext.match(/\b(\d+)\s*(?:baГ±o|baГ±os)\b/);
  if (baГ±oMatch) {
    caracBuscadas.push(`${baГ±oMatch[1]} baГ±os`);
  }

  const extrasRegex = /\b(balcГіn|balcon|terraza|jardГ­n|jardin|patio|parrilla|quincho|cochera|garage|amenities|gym|gimnasio|piscina|pileta|sum|lavadero|baulera)\b/g;
  const extras = fullContext.match(extrasRegex);
  if (extras) {
    caracBuscadas.push(...[...new Set(extras)]);
  }

  if (caracBuscadas.length > 0) {
    info.caracteristicas_buscadas = caracBuscadas.join(', ');
    console.log('CaracterГ­sticas:', info.caracteristicas_buscadas);
  }

  // Extraer cГіdigo de propiedad - direcciones
  const direccionMatch = fullContext.match(/\b(\d+\s*(?:y|e\/|esq\.?|bis|entre)\s*\d+(?:\s*y\s*\d+)?)\b/i);
  if (direccionMatch) {
    info.propiedad_interes = direccionMatch[1].toUpperCase();
    console.log('DirecciГіn/Propiedad encontrada:', info.propiedad_interes);
  } else {
    const propPatterns = [
      /\b(?:propiedad|prop|cГіdigo|codigo|cod|id|referencia|ref)[\s:#-]*([a-z0-9]{3,})\b/i,
      /\b(prop[a-z0-9]{2,})\b/i
    ];

    for (const pattern of propPatterns) {
      const propMatch = fullContext.match(pattern);
      if (propMatch && propMatch[1] && propMatch[1].length >= 3 && propMatch[1].length <= 20) {
        const palabrasComunes = ['para', 'por', 'pero', 'porque', 'propiedad', 'puede', 'paso'];
        if (!palabrasComunes.includes(propMatch[1].toLowerCase())) {
          info.propiedad_interes = propMatch[1].toUpperCase();
          console.log('CГіdigo propiedad encontrado:', info.propiedad_interes);
          break;
        }
      }
    }
  }

  // рџ†• EXTRAER NOMBRE - CON PUSHNAME COMO FALLBACK
  const nombreMatch = userMsg.match(/\b(?:me llamo|mi nombre es|soy|mi nombre)\s+([a-zГЎГ©Г­ГіГєГ±]+(?:\s+[a-zГЎГ©Г­ГіГєГ±]+)?)/i);
  if (nombreMatch) {
    const nombre = nombreMatch[1].trim();
    info.nombre = nombre.split(' ').map(word => 
      word.charAt(0).toUpperCase() + word.slice(1).toLowerCase()
    ).join(' ');
    console.log('вњ… Nombre del mensaje:', info.nombre);
  } else if (pushName) {
    info.nombre = pushName.trim();
    console.log('вњ… Nombre del pushName de Chatwoot:', info.nombre);
  }

  return info;
}

// Extraer informaciГіn del lead
const leadInfo = extractLeadInfo(userMessage, agentOutput);

console.log('=== LEAD INFO FINAL ===');
console.log(JSON.stringify(leadInfo, null, 2));

// Construir query SQL - solo con campos no nulos
const fields = [];
const values = [];
const updates = [];

Object.entries(leadInfo).forEach(([key, value]) => {
  if (value !== null && key !== 'whatsapp_id') {
    fields.push(key);
    values.push(value);

    if (key === 'nombre') {
      updates.push(`${key} = COALESCE(NULLIF(EXCLUDED.${key}, ''), leads.${key})`);
    } else if (key === 'estado') {
      // рџ”’ PROTECCIГ“N: llamada, busqueda y visita nunca se pisan desde el UPSERT
      updates.push(`${key} = CASE 
        WHEN leads.${key} IN ('llamada', 'visita', 'busqueda') THEN leads.${key}
        WHEN EXCLUDED.${key} = 'caliente' THEN 'caliente'
        WHEN EXCLUDED.${key} = 'tibio' AND leads.${key} NOT IN ('caliente', 'llamada', 'visita', 'busqueda') THEN 'tibio'
        WHEN leads.${key} IS NULL OR leads.${key} IN ('activo', 'inicial', '') THEN EXCLUDED.${key}
        ELSE COALESCE(EXCLUDED.${key}, leads.${key})
      END`);
    } else {
      updates.push(`${key} = EXCLUDED.${key}`);
    }
  }
});

// Si no hay campos, solo actualizar ultima_interaccion
if (fields.length === 0) {
  fields.push('ultima_interaccion');
  values.push(leadInfo.ultima_interaccion);
  updates.push('ultima_interaccion = EXCLUDED.ultima_interaccion');
}

const query = `
INSERT INTO leads (whatsapp_id, ${fields.join(', ')})
VALUES ($1, ${values.map((_, i) => `$${i + 2}`).join(', ')})
ON CONFLICT (whatsapp_id) 
DO UPDATE SET 
  ${updates.join(',\n  ')},
  updated_at = CURRENT_TIMESTAMP
RETURNING *;
`;

const parameters = [leadInfo.whatsapp_id, ...values];

console.log('=== QUERY FINAL ===');
console.log('Campos a actualizar:', fields);
console.log('Valores:', parameters);

return [{
  json: {
    query: query,
    parameters: parameters,
    leadInfo: leadInfo,
    operation: 'upsert',
    whatsapp_id: leadInfo.whatsapp_id,
    extracted_data: {
      user_message: userMessage.substring(0, 200),
      agent_response: agentOutput.substring(0, 200),
      pushName: pushName
    },
    debug: {
      whatsapp_found: !!whatsappId,
      pushname_found: !!pushName,
      fields_updated: fields,
      user_msg_length: userMessage.length,
      agent_msg_length: agentOutput.length
    }
  }
}];

// ============================================
// NORMALIZAR WEBHOOKS - VERSIГ“N SIMPLE Y SEGURA
// ============================================

try {
  const webhookData = $input.first().json;
  const body = webhookData.body;
  const event = body.event;

  console.log('=== WEBHOOK RECIBIDO ===');
  console.log('Event:', event);

  // ============================================
  // NORMALIZACIГ“N BГЃSICA
  // ============================================

  let normalized = {
    event: event,
    account: body.account || null,
    inbox: body.inbox || null,
    conversation: null,
    message: null,
    sender: null,
    content: null,
    source_id: null,
    timestamp: null
  };

  if (event === 'conversation_created') {
    // ConversaciГіn estГЎ en body directamente
    normalized.conversation = {
      id: body.id,
      inbox_id: body.inbox_id,
      status: body.status,
      contact_inbox: body.contact_inbox,
      messages: body.messages || [],
      meta: body.meta,
      created_at: body.created_at,
      updated_at: body.updated_at
    };

    const firstMessage = body.messages?.[0];
    if (firstMessage) {
      normalized.message = firstMessage;
      normalized.content = firstMessage.content;
      normalized.source_id = firstMessage.source_id;
      normalized.timestamp = firstMessage.created_at;
      normalized.sender = firstMessage.sender;
    }

  } else if (event === 'message_created') {
    // ConversaciГіn estГЎ en body.conversation
    normalized.conversation = body.conversation;
    normalized.message = {
      id: body.id,
      content: body.content,
      message_type: body.message_type,
      created_at: body.created_at,
      source_id: body.source_id,
      sender_id: body.sender?.id
    };
    normalized.content = body.content;
    normalized.source_id = body.source_id;
    normalized.timestamp = body.created_at;
    normalized.sender = body.sender;
  }

  // Datos comunes
  normalized.phone_number = normalized.conversation?.contact_inbox?.source_id;
  normalized.whatsapp_id = normalized.phone_number?.replace('+', '');
  normalized.contact_name = normalized.sender?.name || 'Desconocido';
  normalized.conversation_id = normalized.conversation?.id;
  normalized.inbox_id = normalized.conversation?.inbox_id;

  console.log('Normalizado exitosamente');
  console.log('TelГ©fono:', normalized.phone_number);
  console.log('Evento:', event);

  return [{
    json: {
      ...webhookData,
      normalized: normalized
    }
  }];

} catch (error) {
  console.error('ERROR EN NORMALIZACIГ“N:', error.message);
  console.error('Stack:', error.stack);
  throw error;
}
